%[text] # 例1.1（配列表現）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 画像データのダウンロード
isVerbose = false;
msip.download_img(isVerbose) %[output:8cf2d629]
%%
%[text] ## (a) グレースケール画像
fprintf('(a) グレースケール画像\n') %[output:56501f89]
V = rgb2gray(imread('./data/kodim01.png'));
fprintf('配列次元： D = %d\n',ndims(V)) %[output:5d9f6771]
imshow(V) %[output:76c5fcf6]
%%
%[text] ## (b) RGB画像
fprintf('(b) RGBカラー画像\n') %[output:891b58cd]
V = imread('./data/kodim23.png');
fprintf('配列次元： D = %d\n',ndims(V)) %[output:06990afa]
imshow(V) %[output:738d8a9f]
%%
%[text] ## (c) 動画像
fprintf('(c) 動画像\n') %[output:59b4d43c]
vrObj = VideoReader('shuttle.avi');
V = zeros(vrObj.Height,vrObj.Width,3,2,'uint8');
V(:,:,:,1) = readFrame(vrObj);
V(:,:,:,2) = readFrame(vrObj);
fprintf('配列次元： D = %d\n',ndims(V)) %[output:06176448]
imshow(V(:,:,:,1)) %[output:0430f610]
title('第0フレーム') %[output:0430f610]
imshow(V(:,:,:,2)) %[output:261f99b1]
title('第1フレーム') %[output:261f99b1]
%%
%[text] ## (d) ボリュームデーデータ
fprintf('(d) ボリュームデータ\n') %[output:773f1585]
load mri
V = squeeze(D);
fprintf('配列次元： D = %d\n',ndims(V)) %[output:6d848dd7]
imshow(V(:,:,1)) %[output:82cdc503]
title('第0スライス(xy)') %[output:82cdc503]
imshow(V(:,:,2)) %[output:7a0483fe]
title('第1スライス(xy)') %[output:7a0483fe]
